try:
    from fastApiClient_cli.cli import main as cli_main

except ImportError:  # pragma: no cover
    cli_main = None  # type: ignore


def main() -> None:
    if not cli_main:  # type: ignore[truthy-function]  # ty: ignore[unused-ignore-comment]
        message = 'To use the fastApiClient command, please install "fastApiClient[standard]":\n\n\tpip install "fastApiClient[standard]"\n'
        print(message)
        raise RuntimeError(message)  # noqa: B904
    cli_main()
